package com.chaobo.scm.supplier.interfaces.web;import com.chaobo.scm.common.api.*;import com.chaobo.scm.supplier.application.contract.*;import com.chaobo.scm.supplier.application.shared.CommandResult;import com.chaobo.scm.supplier.infrastructure.security.CommandContextFactory;import jakarta.servlet.http.*;import jakarta.validation.*;import jakarta.validation.constraints.*;import org.springframework.security.core.*;import org.springframework.security.core.annotation.*;import org.springframework.security.oauth2.jwt.*;import org.springframework.web.bind.annotation.*;import java.time.*;
@RestController @RequestMapping("/api/supplier/v1/contracts") public class SupplierContractController{private final SupplierContractApplicationService s;private final CommandContextFactory c;public SupplierContractController(SupplierContractApplicationService s,CommandContextFactory c){this.s=s;this.c=c;}@GetMapping public ApiResponse<PageResult<SupplierContractView>> page(@RequestParam(required=false)Long supplierId,@RequestParam(required=false)Integer status,@RequestParam(required=false)String keyword,@RequestParam(defaultValue="1")int pageNo,@RequestParam(defaultValue="20")int pageSize,@AuthenticationPrincipal Jwt j,HttpServletRequest r){return ApiResponse.success(s.page(supplierId,scope(j),status,keyword,pageNo,pageSize),r.getHeader("X-Request-Id"),r.getHeader("X-Trace-Id"));}@GetMapping("/{id}")public ApiResponse<SupplierContractView> detail(@PathVariable long id,@AuthenticationPrincipal Jwt j,HttpServletRequest r){return ApiResponse.success(s.detail(id,scope(j)),r.getHeader("X-Request-Id"),r.getHeader("X-Trace-Id"));}@PostMapping public ApiResponse<CommandResult> create(@Valid @RequestBody Create b,HttpServletRequest r,Authentication a){return ok(s.create(b.supplierId(),b.quoteId(),b.priceAgreementRef(),b.contractType(),b.effectiveFrom(),b.effectiveTo(),b.termsJson(),b.attachmentUrl(),c.create(r,a)),r);}@PutMapping("/{id}")public ApiResponse<CommandResult> modify(@PathVariable long id,@Valid @RequestBody Modify b,HttpServletRequest r,Authentication a){return ok(s.modifyDraft(id,b.version(),b.effectiveTo(),b.termsJson(),b.attachmentUrl(),c.create(r,a)),r);}@PostMapping("/{id}/submit")public ApiResponse<CommandResult> submit(@PathVariable long id,@Valid @RequestBody V b,HttpServletRequest r,Authentication a){return ok(s.submit(id,b.version(),c.create(r,a)),r);}@PostMapping("/{id}/activate")public ApiResponse<CommandResult> activate(@PathVariable long id,@Valid @RequestBody V b,HttpServletRequest r,Authentication a){return ok(s.activate(id,b.version(),c.create(r,a)),r);}@PostMapping("/{id}/renew")public ApiResponse<CommandResult> renew(@PathVariable long id,@Valid @RequestBody Renew b,HttpServletRequest r,Authentication a){return ok(s.renew(id,b.version(),b.effectiveTo(),c.create(r,a)),r);}@PostMapping("/{id}/terminate")public ApiResponse<CommandResult> terminate(@PathVariable long id,@Valid @RequestBody Terminate b,HttpServletRequest r,Authentication a){return ok(s.terminate(id,b.version(),b.reason(),c.create(r,a)),r);}private ApiResponse<CommandResult> ok(CommandResult x,HttpServletRequest r){return ApiResponse.success(x,r.getHeader("X-Request-Id"),r.getHeader("X-Trace-Id"));}private Long scope(Jwt j){Number n=j.hasClaim("supplier_id")?j.getClaim("supplier_id"):null;return n==null?null:n.longValue();}public record Create(@Positive long supplierId,Long quoteId,String priceAgreementRef,@NotBlank String contractType,@NotNull LocalDate effectiveFrom,@NotNull LocalDate effectiveTo,@NotBlank String termsJson,@NotBlank String attachmentUrl){}public record Modify(@PositiveOrZero int version,@NotNull LocalDate effectiveTo,@NotBlank String termsJson,@NotBlank String attachmentUrl){}public record V(@PositiveOrZero int version){}public record Renew(@PositiveOrZero int version,@NotNull LocalDate effectiveTo){}public record Terminate(@PositiveOrZero int version,@NotBlank String reason){}}
